import {OurToaster} from "./OurToaster";
import {Intent} from "@blueprintjs/core/lib/esm/common/intent";

export const Pending: FunctionComponent = observer(() => {
  return (
    <div>
      <H1>Pending</H1>
      <H2>
        Bienvenue {ctx.store.getName()}, vous êtes{" "}
        {ctx.store.getRole() === "client"
          ? "client"
          : ctx.store.getRole() === "banker"
          ? "banquier"
          : "client en attente"}{" "}
        chez Heabank !
      </H2>
    </div>
  );
});
